          <FilterSidebar
            filters={filters}
            onFiltersChange={handleFiltersChange}
            onClose={() => setFiltersOpen(false)}
            licensors={licensors}
            properties={properties}
            facetCounts={facetCounts ?? null}
            customerOptions={pathFacets?.customers ?? []}
            programOptions={pathFacets?.programs ?? []}
            mode={libraryMode === "assets" ? "assets" : "groups"}
          />
        )}

        <div className="flex flex-1 flex-col overflow-auto">
          {isGroupsMode ? (
            viewMode === "grid" ? (
              <StyleGroupGrid
                groups={groups}
                selectedIds={selectedIds}
                onSelect={handleSelect}
                isLoading={isLoading}
                rebuildHint={groups.length === 0 && ((totalGroupCount ?? 0) > 0 || (ungroupedCount ?? 0) > 0)}
                cardStyle={cardStyle}
              />
            ) : (
              <StyleGroupListView
                groups={groups}
                selectedIds={selectedIds}
                onSelect={handleSelect}
                isLoading={isLoading}
                rebuildHint={groups.length === 0 && ((totalGroupCount ?? 0) > 0 || (ungroupedCount ?? 0) > 0)}
              />
            )
          ) : (
            viewMode === "grid" ? (
              <AssetGrid
                assets={assets}
                selectedIds={selectedIds}
                onSelect={handleSelect}
                onOpenDetail={setDetailAssetId}
                isLoading={isLoading}
              />
            ) : (
              <AssetListView
                assets={assets}
                selectedIds={selectedIds}
                onSelect={handleSelect}
                isLoading={isLoading}
              />
            )
          )}

          <div className="mt-auto">
            <PaginationBar
              page={page}
              totalCount={count}
              pageSize={pageSize}
              onPageChange={setPage}
              onPageSizeChange={(size) => { setPageSize(size); setPage(0); }}
            />
          </div>
        </div>

        {/* Detail panel: style group */}
        {isGroupsMode && detailGroup && (
          <div className="h-full max-[1399px]:absolute max-[1399px]:inset-y-0 max-[1399px]:right-0 max-[1399px]:z-20 max-[1399px]:shadow-xl">
            <StyleGroupDetailPanel
              key={detailGroup.id}
              group={detailGroup}
              onClose={() => setDetailGroupId(null)}
            />
          </div>
        )}

        {/* Detail panel: individual asset */}
        {!isGroupsMode && detailAsset && (
          <div className="h-full max-[1399px]:absolute max-[1399px]:inset-y-0 max-[1399px]:right-0 max-[1399px]:z-20 max-[1399px]:shadow-xl">
            <AssetDetailPanel
              asset={detailAsset}
              onClose={() => setDetailAssetId(null)}
              onOpenGroup={(groupId) => {
                handleLibraryModeChange("groups");
                setDetailGroupId(groupId);
              }}
            />
          </div>
        )}
      </div>
    </div>
  );
}

