1	import { useEffect, useRef } from "react";
2	import { useMutation, useQueryClient } from "@tanstack/react-query";
3	import { supabase } from "@/integrations/supabase/client";
4	import type { StyleGroup } from "@/hooks/useStyleGroups";
5	import type { Enums } from "@/integrations/supabase/types";
6	import { Button } from "@/components/ui/button";
7	import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
8	import { Badge } from "@/components/ui/badge";
9	import { Progress } from "@/components/ui/progress";
10	import {
11	  Select,
12	  SelectContent,
13	  SelectItem,
14	  SelectTrigger,
15	  SelectValue,
16	} from "@/components/ui/select";
17	import { X, Sparkles, ArrowRightLeft, Loader2, CheckCircle2, AlertCircle, Square } from "lucide-react";
18	import { Constants } from "@/integrations/supabase/types";
19	import { toast } from "sonner";
20	import { usePersistentOperation } from "@/hooks/usePersistentOperation";
21	import { useState } from "react";
22	
23	interface BulkActionBarProps {
24	  selectedGroups: StyleGroup[];
25	  onClearSelection: () => void;
26	}
27	
28	export default function BulkActionBar({ selectedGroups, onClearSelection }: BulkActionBarProps) {
29	  const queryClient = useQueryClient();
30	  const [workflowValue, setWorkflowValue] = useState<string>("");
31	
32	  const op = usePersistentOperation("ai-tag-groups");
33	
34	  // Start server-side AI tagging for selected groups
35	  const handleBulkAiTag = async () => {
36	    const groupIds = selectedGroups.map(g => g.id);
37	    // Count taggable assets for progress display
38	    const { count, error } = await supabase
39	      .from("assets")
40	      .select("id", { count: "exact", head: true })
41	      .in("style_group_id", groupIds)
42	      .eq("is_deleted", false)
43	      .not("thumbnail_url", "is", null);
44	
45	    if (error) {
46	      toast.error("Failed to count assets", { description: error.message });
47	      return;
48	    }
49	
50	    if (!count || count === 0) {
51	      toast.error("No taggable assets", { description: "Selected groups have no assets with thumbnails." });
52	      return;
53	    }
54	
55	    await op.start({
56	      params: { type: "bulk-ai-tag-all", group_ids: groupIds, total: count },
57	      initialProgress: { tagged: 0, skipped: 0, failed: 0, total: count },
58	    });
59	
60	    toast(`AI tagging ${count} asset${count !== 1 ? "s" : ""} across ${selectedGroups.length} group${selectedGroups.length !== 1 ? "s" : ""}…`);
61	  };
62	
63	  // Invalidate queries when operation completes
64	  const progress = op.state.progress ?? {};
65	  const isRunning = op.isActive;
66	  const isDone = op.state.status === "completed";
67	  const isFailed = op.state.status === "failed";
68	
69	  // Auto-invalidate on completion (once per transition)
70	  const prevDoneRef = useRef(false);
71	  useEffect(() => {
72	    if ((isDone || isFailed) && !prevDoneRef.current) {
73	      queryClient.invalidateQueries({ queryKey: ["style-groups"] });
74	    }
75	    prevDoneRef.current = isDone || isFailed;
76	  }, [isDone, isFailed, queryClient]);
77	
78	  const total = (progress.total as number) || 0;
79	  const tagged = (progress.tagged as number) || 0;
80	  const skipped = (progress.skipped as number) || 0;
81	  const failed = (progress.failed as number) || 0;
82	  const processed = tagged + skipped + failed;
83	  const progressPercent = total > 0 ? Math.round((processed / total) * 100) : 0;
84	
85	  // Bulk workflow change — update style_groups directly
86	  const bulkWorkflow = useMutation({
87	    mutationFn: async (status: string) => {
88	      const ids = selectedGroups.map((g) => g.id);
89	      const { data, error } = await supabase
90	        .from("style_groups")
91	        .update({ workflow_status: status as Enums<"workflow_status"> })
92	        .in("id", ids)
93	        .select("id");
94	      if (error) throw error;
95	      if (!data || data.length === 0) throw new Error("Update was blocked — you may not have permission to change workflow status");
96	    },
97	    onSuccess: () => {
98	      queryClient.invalidateQueries({ queryKey: ["style-groups"] });
99	      toast(`Workflow updated for ${selectedGroups.length} group${selectedGroups.length !== 1 ? "s" : ""}`);
100	      setWorkflowValue("");
101	    },
102	    onError: (e) => {
103	      toast.error("Bulk update failed", { description: e.message });
104	    },
105	  });
106	
107	  return (
108	    <div className="flex items-center gap-3 border-b border-primary/30 bg-primary/5 px-4 py-2.5 animate-in slide-in-from-top duration-200">
109	      {/* Selection count */}
110	      <div className="flex items-center gap-2">
111	        <Badge variant="default" className="text-xs">
112	          {selectedGroups.length} group{selectedGroups.length !== 1 ? "s" : ""} selected
113	        </Badge>
114	        <Button variant="ghost" size="icon" className="h-6 w-6" onClick={onClearSelection}>
115	          <X className="h-3.5 w-3.5" />
116	        </Button>
117	      </div>
118	
119	      {/* AI Tag button */}
120	      <TooltipProvider>
121	        <Tooltip>
122	          <TooltipTrigger asChild>
123	            {isRunning ? (
124	              <Button
125	                variant="outline"
126	                size="sm"
127	                className="h-8 gap-1.5"
128	                onClick={() => op.stop()}
129	              >
130	                <Square className="h-3 w-3 fill-current" />
131	                Stop
